# Check if there's a CA key in any Kubernetes secret
kubectl -n demo get secrets -o json 2>&1 | python3 -c "
import json, sys, base64
data = json.load(sys.stdin)
for item in data.get('items', []):
    name = item['metadata']['name']
    for k, v in item.get('data', {}).items():
        try:
            decoded = base64.b64decode(v).decode('utf-8', errors='replace')
            if 'PRIVATE KEY' in decoded:
                print(f'{name}/{k}: has private key')
        except:
            pass
" 2>&1

# Check other namespaces for secrets with CA keys
kubectl get secrets --all-namespaces -o json 2>&1 | python3 -c "
import json, sys, base64
data = json.load(sys.stdin)
for item in data.get('items', []):
    name = item['metadata']['name']
    ns = item['metadata']['namespace']
    for k, v in item.get('data', {}).items():
        try:
            decoded = base64.b64decode(v).decode('utf-8', errors='replace')
            if 'PRIVATE KEY' in decoded:
                # Get its public key fingerprint
                print(f'{ns}/{name}/{k}: has private key (len={len(decoded)})')
        except:
            pass
" 2>&1 | head -30
